        if (data_bits_enc == 2'b01) // 6-bit: BIT5 is last data bit
                        next_state = parity_en ? TX_PARITY : TX_STOP1;
                    else
                        next_state = TX_BIT6;
                end else
                    next_state = TX_BIT5;
            end

            TX_BIT6: begin
                if (bit_cnt == 4'd15 && enable) begin
                    if (data_bits_enc == 2'b10) // 7-bit: BIT6 is last data bit
                        next_state = parity_en ? TX_PARITY : TX_STOP1;
                    else
                        next_state = TX_BIT7;
                end else
                    next_state = TX_BIT6;
            end

            TX_BIT7: begin // 8-bit: BIT7 is always last data bit
                if (bit_cnt == 4'd15 && enable)
                    next_state = parity_en ? TX_PARITY : TX_STOP1;
                else
                    next_state = TX_BIT7;
            end

            TX_PARITY: begin
                if (bit_cnt == 4'd15 && enable)
                    next_state = TX_STOP1;
                else
                    next_state = TX_PARITY;
            end

            TX_STOP1: begin
                if (bit_cnt == 4'd15 && enable) begin
                    if (!stop_bits_en)
                        next_state = TX_IDLE; // 1 stop bit
                    else if (data_bits_enc == 2'b00) // 5-bit data: 1.5 stop bits
                        next_state = TX_HALF;
                    else
                        next_state = TX_STOP2; // 2 stop bits
                end else
                    next_state = TX_STOP1;
            end

            TX_STOP2: begin
                if (bit_cnt == 4'd15 && enable)
                    next_state = TX_IDLE;
                else
                    next_state = TX_STOP2;
            end

            TX_HALF: begin // 1.5 stop bit: half period (8 PCLK cycles)
                if (bit_cnt == 4'd7 && enable)
                    next_state = TX_IDLE;
                else
                    next_state = TX_HALF;
            end

            default: next_state = TX_IDLE;
        endcase
    end

    //========================================================================
    // FSM: State Register + Data Path Registers
    //========================================================================
    always @(posedge PCLK or negedge PRESETn) begin
        if (!PRESETn) begin
            // Async reset: all registers to initial values
            tx_state   <= TX_IDLE;
            bit_cnt    <= 4'b0;
            bit_index  <= 3'b0;
            tx_buffer  <= 8'b0;
            lcr_latch  <= 8'b0;
            parity_bit <= 1'b0;
            TXD        <= 1'b1;  // Idle line level
            tx_fifo_pop <= 1'b0;
        end else begin
            // Default: pop signal is one-cycle pulse, clear after assertion
            tx_fifo_pop <= 1'b0;

            case (tx_state)
                TX_IDLE: begin
                    bit_cnt <= 4'b0;
                    if (enable && !fifo_empty) begin
                        // Frame start: latch LCR, pop FIFO, load tx_buffer
                        lcr_latch  <= LCR;
                        tx_fifo_pop <= 1'b1;
                        tx_buffer  <= fifo_rd_data & data_mask; // LSB-aligned, upper bits zeroed
                        // Pre-compute parity bit
                        case (parity_type)
                            2'b00: parity_bit <= ^(fifo_rd_data & data_mask); // Even parity
                            2'b01: parity_bit <= ~^(fifo_rd_data & data_mask); // Odd parity
                            2'b10: parity_bit <= 1'b1; // Stick parity 1
                            2'b11: parity_bit <= 1'b0; // Stick parity 0
                            default: parity_bit <= 1'b0;
                        endcase
                        // Note: parity_en comes from LCR[3] which is being latched this cycle
                        // We use LCR directly here since lcr_latch hasn't been updated yet
                        // The parity_bit computation uses LCR[5:4] for type
                        // But parity_en (LCR[3]) determines whether we enter TX_PARITY state
                        // This is handled in next_state logic using lcr_latch after it's latched
                    end
                end

                TX_START: begin
                    if (enable) begin
                        if (bit_cnt == 4'd15) begin
                            bit_cnt   <= 4'b0;
                            bit_index <= 3'b0;
                        end else begin
                            bit_cnt <= bit_cnt + 4'b1;
                        end
                    end
                    // bit_cnt frozen when enable=0
                end

                TX_BIT0, TX_BIT1, TX_BIT2, TX_BIT3,
                TX_BIT4, TX_BIT5, TX_BIT6, TX_BIT7: begin
                    if (enable) begin
                        if (bit_cnt == 4'd15) begin
                            bit_cnt    <= 4'b0;
                            bit_index  <= bit_index + 3'b1;
                        end else begin
                            bit_cnt <= bit_cnt + 4'b1;
                        end
                    end
                    // bit_cnt frozen when enable=0
                end

                TX_PARITY: begin
                    if (enable) begin
                        if (bit_cnt == 4'd15)
                            bit_cnt <= 4'b0;
                        else
                            bit_cnt <= bit_cnt + 4'b1;
                    end
                end

                TX_STOP1: begin
                    if (enable) begin
                        if (bit_cnt == 4'd15)
                            bit_cnt <= 4'b0;
                        else
                            bit_cnt <= bit_cnt + 4'b1;
                    end
                end

                TX_STOP2: begin
                    if (enable) begin
                        if (bit_cnt == 4'd15)
                            bit_cnt <= 4'b0;
                        else
                            bit_cnt <= bit_cnt + 4'b1;
                    end
                end

                TX_HALF: begin
                    if (enable) begin
                        if (bit_cnt == 4'd7)
                            bit_cnt <= 4'b0;
                        else
                            bit_cnt <= bit_cnt + 4'b1;
                    end
                end

                default: ;
            endcase

            // Update state register
            tx_state <= next_state;
        end
    end

    //========================================================================
    // TXD Output Logic (Registered to prevent glitches)
    //========================================================================
    always @(posedge PCLK or negedge PRESETn) begin
        if (!PRESETn) begin
            TXD <= 1'b1; // Idle line level
        end else begin
            case (next_state)
                TX_IDLE:   TXD <= 1'b1;
                TX_START:  TXD <= 1'b0;
                TX_BIT0:   TXD <= tx_buffer[0];
                TX_BIT1:   TXD <= tx_buffer[1];
                TX_BIT2:   TXD <= tx_buffer[2];
                TX_BIT3:   TXD <= tx_buffer[3];
                TX_BIT4:   TXD <= tx_buffer[4];
                TX_BIT5:   TXD <= tx_buffer[5];
                TX_BIT6:   TXD <= tx_buffer[6];
                TX_BIT7:   TXD <= tx_buffer[7];
                TX_PARITY: TXD <= parity_bit;
                TX_STOP1:  TXD <= 1'b1;
                TX_STOP2:  TXD <= 1'b1;
                TX_HALF:   TXD <= 1'b1;
                default:   TXD <= 1'b1;
            endcase
        end
    end

endmodule
